using System.ComponentModel.DataAnnotations;

namespace sv_fc6ac194e70b4cabb89e0c301f7f44d6.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

namespace sv_fc6ac194e70b4cabb89e0c301f7f44d6.Services;

public class ReviewService
{
    /// <summary>
    /// Validates and submits a review. Returns a dictionary of field-specific errors,
    /// or an empty dictionary if submission succeeds.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(
        string productName,
        int rating,
        string reviewTitle,
        string reviewBody,
        List<byte[]>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (reviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(reviewTitle)] = "Review title contains inappropriate language.";
        }

        // Stub: additional server-side validation rules can be added here.

        return Task.FromResult(errors);
    }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_fc6ac194e70b4cabb89e0c301f7f44d6.Models
@using sv_fc6ac194e70b4cabb89e0c301f7f44d6.Services
@inject ReviewService ReviewService

<h3>Write a Review</h3>

@if (_submitted)
{
    <div class="alert alert-success">
        Your review has been submitted successfully. Thank you!
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="_model.ProductName" />
            <ValidationMessage For="() => _model.ProductName" />
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating (1–5)</label>
            <InputNumber id="rating" class="form-control" @bind-Value="_model.Rating" />
            <ValidationMessage For="() => _model.Rating" />
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="_model.ReviewTitle" />
            <ValidationMessage For="() => _model.ReviewTitle" />
            @if (_serverErrors.ContainsKey("reviewTitle"))
            {
                <div class="validation-message">@_serverErrors["reviewTitle"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" rows="5" @bind-Value="_model.ReviewBody" />
            <ValidationMessage For="() => _model.ReviewBody" />
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Upload Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnFilesSelected" multiple accept=".jpg,.jpeg,.png" />
            @if (!string.IsNullOrEmpty(_fileError))
            {
                <div class="validation-message">@_fileError</div>
            }
            @if (_selectedFiles.Count > 0)
            {
                <ul class="mt-2 list-unstyled">
                    @foreach (var file in _selectedFiles)
                    {
                        <li><strong>@file.Name</strong> — @FormatSize(file.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
            @if (_isSubmitting)
            {
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewModel _model = new();
    private List<IBrowserFile> _selectedFiles = new();
    private List<byte[]> _photoData = new();
    private Dictionary<string, string> _serverErrors = new();
    private string? _fileError;
    private bool _submitted;
    private bool _isSubmitting;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFiles = 3;
    private static readonly string[] AllowedContentTypes = { "image/jpeg", "image/png" };

    private void OnFilesSelected(InputFileChangeEventArgs e)
    {
        _fileError = null;
        _selectedFiles.Clear();
        _photoData.Clear();

        var files = e.GetMultipleFiles(MaxFiles);

        if (e.FileCount > MaxFiles)
        {
            _fileError = $"You can upload a maximum of {MaxFiles} photos.";
            return;
        }

        foreach (var file in files)
        {
            if (!AllowedContentTypes.Contains(file.ContentType))
            {
                _fileError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
                _selectedFiles.Clear();
                return;
            }

            if (file.Size > MaxFileSize)
            {
                _fileError = $"'{file.Name}' exceeds the 5 MB size limit.";
                _selectedFiles.Clear();
                return;
            }

            _selectedFiles.Add(file);
        }
    }

    private async Task HandleSubmit()
    {
        _serverErrors.Clear();
        _isSubmitting = true;

        try
        {
            // Read photo data only if not already loaded (preserves across resubmission)
            if (_photoData.Count == 0 && _selectedFiles.Count > 0)
            {
                foreach (var file in _selectedFiles)
                {
                    using var stream = file.OpenReadStream(MaxFileSize);
                    using var ms = new MemoryStream();
                    await stream.CopyToAsync(ms);
                    _photoData.Add(ms.ToArray());
                }
            }

            var errors = await ReviewService.ValidateAndSubmitAsync(
                _model.ProductName,
                _model.Rating!.Value,
                _model.ReviewTitle,
                _model.ReviewBody,
                _photoData.Count > 0 ? _photoData : null);

            if (errors.Count > 0)
            {
                _serverErrors = errors;
            }
            else
            {
                _submitted = true;
            }
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

